/**
 * Session Utils Extension
 * 
 * Provides:
 * - /save - Save session and display session ID for later resuming
 * - /list-sessions - List all sessions interactively (uses SessionManager from core)
 * 
 * Since this extension lives in ~/.pi/agent/extensions/, it will be
 * synced across devices when using stow with dotfiles.
 */

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { SessionManager } from "@mariozechner/pi-coding-agent";

export default function (pi: ExtensionAPI) {
    // Register /save command
    pi.registerCommand("save", {
        description: "Save session and display session ID for later resuming",
        handler: async (args, ctx) => {
            const sessionManager = ctx.sessionManager;
            const sessionId = sessionManager.getSessionId();
            const sessionFile = sessionManager.getSessionFile();
            const sessionName = sessionManager.getSessionName();

            let message = `✅ Session Saved!\n\n`;
            if (sessionName) {
                message += `Name: ${sessionName}\n`;
            }
            message += `Session ID: ${sessionId}\n`;
            message += `File: ${sessionFile ?? "In-memory"}\n\n`;
            message += `To resume this session later, use:\n`;
            message += `  pi --session ${sessionId}\n`;
            if (sessionFile) {
                message += `  pi --session ${sessionFile}\n`;
            }

            ctx.ui.notify(message, "info");
        },
    });

    // Register /list-sessions command (interactive mode)
    pi.registerCommand("list-sessions", {
        description: "List all sessions and optionally resume one",
        handler: async (args, ctx) => {
            const sessions = await SessionManager.listAll();

            if (sessions.length === 0) {
                ctx.ui.notify("No sessions found.", "info");
                return;
            }

            const items = sessions.map((s) => {
                const name = s.name ? s.name : "(unnamed)";
                const shortId = s.id.slice(0, 8);
                const date = s.modified.toLocaleDateString();
                return `${shortId} | ${name} | ${s.cwd} | ${date}`;
            });

            const selected = await ctx.ui.select("All Sessions (select to copy ID)", items);

            if (selected) {
                // Extract session ID from selected string
                const sessionId = selected.split(" | ")[0];
                ctx.ui.notify(`To resume: pi --session ${sessionId}`, "info");
            }
        },
    });
}

